mapper.sql:
SELECT A.SBJCT_TMPLT_ID , A.SBJCTNM , A.SBJCT_YR , A.SBJCT_SMSTR , A.DEPT_ID , A.SBJCT_GBNCD , A.SBJCT_TYCD , A.USEYN , A.DELYN , B.SMSTR_CHRT_ID , B.ORG_ID , B.DGRS_YR , B.DGRS_SMSTR_CHRT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT FROM DEV_LMS.TB_LMS_SBJCT_TMPLT A INNER JOIN DEV_LMS.TB_LMS_SMSTR_CHRT B ON B.SMSTR_CHRT_ID = A.SMSTR_CHRT_ID WHERE 1 = 1 AND A.DELYN = 'N'
AND B.ORG_ID = #{orgId}
AND A.SBJCT_YR = #{sbjctYr}
AND TRIM(A.SBJCT_SMSTR) = #{sbjctSmstr}
AND A.SBJCT_TYCD = #{sbjctTycd}
AND A.SBJCTNM LIKE FN_LIKE_VAL(#{searchValue})
ORDER BY A.REG_DTTM DESC

mapper.update:
/* 
    SQL ID : SbjctDAO.updateSbjctUseYn
    설명 : 과목사용여부 수정
*/

UPDATE TB_LMS_SBJCT_MSTR
   SET USEYN    = #{useYn},
       MDFR_ID  = #{mdfrId},
       MOD_DTTM = #{modDttm}
 WHERE SBJCT_TMPLT_ID = #{sbjctMstrId}
   AND DELYN = 'N'

/* 
    SQL ID : SbjctDAO.ProcessVo
    설명 : 과목삭제(논리삭제)
*/

UPDATE TB_LMS_SBJCT_MSTR
   SET DELYN    = 'Y',
       MDFR_ID  = #{mdfrId},
       MOD_DTTM = #{modDttm}
 WHERE SBJCT_TMPLT_ID = #{sbjctMstrId}
   AND DELYN = 'N'
